    // Precompute prefix maximums: max_prefix[i] = max(nums[0]...nums[i])
    val maxPrefix = LongArray(n)
    var currentMax = Long.MIN_VALUE
    for (i in 0 until n) {
        currentMax = maxOf(currentMax, nums[i])
        maxPrefix[i] = currentMax
    }

    // Precompute suffix minimums: min_suffix[i] = min(nums[i]...nums[n-1])
    val minSuffix = LongArray(n)
    var currentMin = Long.MAX_VALUE
    for (i in n - 1 downTo 0) {
        currentMin = minOf(currentMin, nums[i])
        minSuffix[i] = currentMin
    }

    // Iterate through all indices i to find the smallest stable index
    for (i in 0 until n) {
        // Unstable value for index i is max(nums[0..i]) - min(nums[i..n-1])
        val unstableValue = maxPrefix[i] - minSuffix[i]

        // Check if it is a stable index
        if (unstableValue <= k) {
            return i.toLong()
        }
    }

    // If no stable index is found
    return -1L
}
